import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model.{ContentTypes, HttpEntity, HttpRequest, HttpResponse}
import akka.stream.ActorMaterializer
import spray.json._

import scala.concurrent.ExecutionContext.Implicits.global

object WebhookProxyService extends App {
  implicit val system = ActorSystem()
  implicit val materializer = ActorMaterializer()

  def route:akka.http.scaladsl.server.Route =
    path("fetch") {
      post {
        entity(as[String]) { url =>
          val request = HttpRequest(uri = url)
          onComplete(Http().singleRequest(request)) {
            case scala.util.Success(response) =>
              complete(response.entity.dataBytes.map(_.utf8String).runFold("")(_ ++ _))
            case scala.util.Failure(exception) =>
              complete(HttpResponse(status = 500, entity = HttpEntity(ContentTypes.`text/plain(UTF-8)`, s"Error: ${exception.getMessage}")))
          }
        }
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)

  println(s"Server online at http://localhost:8080/")
}